@inject NavigationManager Navigation

@code {
    protected override void OnInitialized()
    {
        var returnUrl = Uri.EscapeDataString(Navigation.ToBaseRelativePath(Navigation.Uri));
        Navigation.NavigateTo($"account/login?returnUrl=/{returnUrl}", forceLoad: true);
    }
}

@page "/account/login"
@using Microsoft.AspNetCore.Identity
@inject SignInManager<IdentityUser> SignInManager
@inject NavigationManager Navigation

<PageTitle>Login</PageTitle>

<div class="row justify-content-center mt-5">
    <div class="col-md-4">
        <h2 class="text-center mb-4">Login</h2>

        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        <EditForm Model="loginModel" FormName="login" OnValidSubmit="HandleLogin" method="post">
            <DataAnnotationsValidator />
            <AntiforgeryToken />

            <div class="mb-3">
                <label for="email" class="form-label">Email</label>
                <InputText id="email" @bind-Value="loginModel.Email" class="form-control" placeholder="email@company.com" />
                <ValidationMessage For="() => loginModel.Email" />
            </div>

            <div class="mb-3">
                <label for="password" class="form-label">Password</label>
                <InputText id="password" @bind-Value="loginModel.Password" type="password" class="form-control" />
                <ValidationMessage For="() => loginModel.Password" />
            </div>

            <button type="submit" class="btn btn-primary w-100">Sign In</button>
        </EditForm>

        <div class="mt-4 text-muted small">
            <p class="mb-1"><strong>Test accounts:</strong></p>
            <ul class="mb-0">
                <li>admin&#64;company.com</li>
                <li>manager&#64;company.com</li>
                <li>employee&#64;company.com</li>
            </ul>
            <p class="mb-0">Password: <code>Test123!</code></p>
        </div>
    </div>
</div>

@code {
    [SupplyParameterFromForm]
    private LoginModel loginModel { get; set; } = new();

    [SupplyParameterFromQuery]
    private string? returnUrl { get; set; }

    private string? errorMessage;

    private async Task HandleLogin()
    {
        var result = await SignInManager.PasswordSignInAsync(
            loginModel.Email, loginModel.Password, isPersistent: false, lockoutOnFailure: false);

        if (result.Succeeded)
        {
            Navigation.NavigateTo(returnUrl ?? "/", forceLoad: true);
        }
        else
        {
            errorMessage = "Invalid email or password.";
        }
    }

    private sealed class LoginModel
    {
        [System.ComponentModel.DataAnnotations.Required]
        [System.ComponentModel.DataAnnotations.EmailAddress]
        public string Email { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required]
        public string Password { get; set; } = "";
    }
}

@page "/account/logout"
@using Microsoft.AspNetCore.Identity
@inject SignInManager<IdentityUser> SignInManager
@inject NavigationManager Navigation

<PageTitle>Logging out...</PageTitle>

@code {
    protected override async Task OnInitializedAsync()
    {
        await SignInManager.SignOutAsync();
        Navigation.NavigateTo("/account/login", forceLoad: true);
    }
}

@page "/admin/users"
@rendermode InteractiveServer
@attribute [Authorize(Roles = "Admin")]
@using Microsoft.AspNetCore.Identity
@inject UserManager<IdentityUser> UserManager

<PageTitle>User Management</PageTitle>

<h1>User Management</h1>
<p class="text-muted">All registered users and their assigned roles.</p>

@if (users is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Email</th>
                <th>Username</th>
                <th>Roles</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var (user, roles) in users)
            {
                <tr>
                    <td>@user.Email</td>
                    <td>@user.UserName</td>
                    <td>
                        @foreach (var role in roles)
                        {
                            <span class="badge bg-primary me-1">@role</span>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<(IdentityUser User, IList<string> Roles)>? users;

    protected override async Task OnInitializedAsync()
    {
        var allUsers = UserManager.Users.ToList();
        var result = new List<(IdentityUser, IList<string>)>();

        foreach (var user in allUsers)
        {
            var roles = await UserManager.GetRolesAsync(user);
            result.Add((user, roles));
        }

        users = result;
    }
}

@page "/directory"
@rendermode InteractiveServer
@attribute [Authorize]

<PageTitle>Employee Directory</PageTitle>

<h1>Employee Directory</h1>
<p class="text-muted">Accessible to all authenticated users.</p>

<table class="table table-striped">
    <thead>
        <tr>
            <th>Name</th>
            <th>Department</th>
            <th>Email</th>
            <th>Extension</th>
        </tr>
    </thead>
    <tbody>
        @foreach (var emp in employees)
        {
            <tr>
                <td>@emp.Name</td>
                <td>@emp.Department</td>
                <td>@emp.Email</td>
                <td>@emp.Extension</td>
            </tr>
        }
    </tbody>
</table>

@code {
    private readonly List<Employee> employees =
    [
        new("Alice Johnson", "Engineering", "alice@company.com", "x1001"),
        new("Bob Smith", "Marketing", "bob@company.com", "x1002"),
        new("Carol Williams", "Human Resources", "carol@company.com", "x1003"),
        new("David Brown", "Finance", "david@company.com", "x1004"),
        new("Eve Davis", "Engineering", "eve@company.com", "x1005"),
    ];

    private record Employee(string Name, string Department, string Email, string Extension);
}

